sys_script_include.script:
var McSimUtil = Class.create();
McSimUtil.prototype = {
    simulateThroughput: function (days, iterations, dailyThroughput) {
        var results = [];
        for (var i = 0; i < iterations; i++) {
            var totalThroughput = 0;
            for (var j = 0; j < days; j++) {
                var randomIndex = Math.floor(Math.random() * dailyThroughput.length);
                totalThroughput += dailyThroughput[randomIndex];
            }
            results.push(totalThroughput);
        }

        // Debugging: Erste 10 Ergebnisse ausgeben
        gs.info("Simulation Results (first 10): " + JSON.stringify(results.slice(0, 10)));

        return results;
    },

    calculateProbability: function (targetThroughput, simulationResults) {
        var successCount = simulationResults.filter(function (result) {
            return result >= targetThroughput;
        }).length;

        var probability = (successCount / simulationResults.length) * 100;
        return probability;
    },

    calculatePercentile: function (simulationResults, confidenceLevel) {
        simulationResults.sort(function (a, b) {
            return a - b;
        });

        var index = Math.floor((1 - confidenceLevel / 100) * simulationResults.length);
        return simulationResults[Math.min(simulationResults.length - 1, Math.max(0, index))];
    },

    type: 'McSimUtil'
};
